namespace RecipeCommunity.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

using RecipeCommunity.Models;

namespace RecipeCommunity.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes =
    [
        new()
        {
            Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
            Description = "A simple yet delicious pizza with fresh mozzarella, tomatoes, and basil.",
            Ingredients = ["Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt"],
            Steps = [
                "Preheat oven to 475°F (245°C) with a pizza stone inside.",
                "Roll out the dough on a floured surface to a 12-inch circle.",
                "Spread crushed tomatoes evenly, leaving a 1-inch border.",
                "Tear mozzarella into pieces and distribute over the sauce.",
                "Bake for 10–12 minutes until crust is golden and cheese is bubbly.",
                "Top with fresh basil leaves and a drizzle of olive oil."
            ],
            AverageRating = 4.5, RatingCount = 24
        },
        new()
        {
            Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
            Description = "Creamy Roman pasta made with eggs, cheese, pancetta, and pepper.",
            Ingredients = ["Spaghetti", "Pancetta", "Eggs", "Pecorino Romano", "Black pepper", "Salt"],
            Steps = [
                "Cook spaghetti in salted boiling water until al dente.",
                "Fry pancetta in a skillet until crispy.",
                "Whisk eggs and grated Pecorino together in a bowl.",
                "Drain pasta, reserving 1 cup of pasta water.",
                "Toss hot pasta with pancetta, then remove from heat.",
                "Stir in egg mixture quickly, adding pasta water to create a creamy sauce.",
                "Season generously with black pepper and serve immediately."
            ],
            AverageRating = 4.8, RatingCount = 42
        },
        new()
        {
            Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
            Description = "Tender chicken pieces in a rich, spiced tomato-cream sauce.",
            Ingredients = ["Chicken breast", "Yogurt", "Garam masala", "Tomato sauce", "Heavy cream", "Onion", "Garlic", "Ginger", "Cumin", "Turmeric"],
            Steps = [
                "Marinate chicken in yogurt, garam masala, and turmeric for at least 1 hour.",
                "Grill or broil chicken until charred and cooked through.",
                "Sauté onion, garlic, and ginger in oil until softened.",
                "Add cumin, garam masala, and tomato sauce; simmer for 15 minutes.",
                "Stir in heavy cream and the cooked chicken.",
                "Simmer for another 10 minutes. Serve over basmati rice."
            ],
            AverageRating = 4.7, RatingCount = 38
        },
        new()
        {
            Id = 4, Title = "Vegetable Biryani", Category = "Indian",
            Description = "Fragrant layered rice dish with mixed vegetables and aromatic spices.",
            Ingredients = ["Basmati rice", "Mixed vegetables", "Onions", "Saffron", "Cardamom", "Cinnamon", "Bay leaves", "Ghee", "Mint leaves", "Cilantro"],
            Steps = [
                "Soak basmati rice for 30 minutes, then parboil until 70% cooked.",
                "Fry sliced onions in ghee until deep golden brown.",
                "Cook vegetables with spices until tender.",
                "Layer rice and vegetables in a heavy-bottomed pot.",
                "Add saffron milk, fried onions, mint, and cilantro between layers.",
                "Seal the pot and cook on low heat for 25 minutes.",
                "Gently fluff and serve with raita."
            ],
            AverageRating = 4.3, RatingCount = 19
        },
        new()
        {
            Id = 5, Title = "Tacos al Pastor", Category = "Mexican",
            Description = "Marinated pork tacos inspired by Lebanese shawarma, with pineapple and cilantro.",
            Ingredients = ["Pork shoulder", "Dried guajillo chiles", "Pineapple", "Corn tortillas", "Onion", "Cilantro", "Lime", "Achiote paste"],
            Steps = [
                "Blend guajillo chiles, achiote paste, pineapple juice, and spices into a marinade.",
                "Marinate thinly sliced pork for at least 4 hours.",
                "Grill or pan-fry pork slices until charred at the edges.",
                "Warm corn tortillas on a dry skillet.",
                "Assemble tacos with pork, diced pineapple, onion, and cilantro.",
                "Squeeze fresh lime over the top and serve."
            ],
            AverageRating = 4.6, RatingCount = 31
        },
        new()
        {
            Id = 6, Title = "Guacamole", Category = "Mexican",
            Description = "Fresh and chunky avocado dip with lime, cilantro, and jalapeño.",
            Ingredients = ["Avocados", "Lime juice", "Cilantro", "Red onion", "Jalapeño", "Tomato", "Salt", "Garlic"],
            Steps = [
                "Halve and pit ripe avocados; scoop into a bowl.",
                "Mash to desired consistency with a fork.",
                "Stir in finely diced onion, jalapeño, tomato, and minced garlic.",
                "Add chopped cilantro and fresh lime juice.",
                "Season with salt to taste.",
                "Serve immediately with tortilla chips."
            ],
            AverageRating = 4.4, RatingCount = 56
        },
        new()
        {
            Id = 7, Title = "Chocolate Lava Cake", Category = "Desserts",
            Description = "Individual cakes with a warm, molten chocolate center.",
            Ingredients = ["Dark chocolate", "Butter", "Eggs", "Sugar", "Flour", "Vanilla extract", "Salt"],
            Steps = [
                "Preheat oven to 425°F (220°C). Grease and flour ramekins.",
                "Melt chocolate and butter together; let cool slightly.",
                "Whisk eggs, sugar, and vanilla until thick and pale.",
                "Fold chocolate mixture into the eggs, then fold in flour and salt.",
                "Divide batter among ramekins.",
                "Bake for 12–14 minutes until edges are set but center is soft.",
                "Invert onto plates and serve immediately with whipped cream."
            ],
            AverageRating = 4.9, RatingCount = 67
        },
        new()
        {
            Id = 8, Title = "Classic Cheesecake", Category = "Desserts",
            Description = "Rich and creamy New York-style cheesecake with a graham cracker crust.",
            Ingredients = ["Cream cheese", "Sugar", "Eggs", "Sour cream", "Vanilla extract", "Graham crackers", "Butter", "Lemon zest"],
            Steps = [
                "Crush graham crackers and mix with melted butter; press into springform pan.",
                "Bake crust at 325°F (160°C) for 10 minutes.",
                "Beat cream cheese and sugar until smooth.",
                "Add eggs one at a time, then mix in sour cream, vanilla, and lemon zest.",
                "Pour filling over crust and bake for 55–60 minutes.",
                "Turn off oven, crack the door, and let cake cool inside for 1 hour.",
                "Refrigerate for at least 4 hours before serving."
            ],
            AverageRating = 4.6, RatingCount = 44
        },
    ];

    private int _nextId = 9;

    public IReadOnlyList<string> GetCategories()
    {
        return _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();
    }

    public IReadOnlyList<Recipe> GetByCategory(string category)
    {
        return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    public Recipe? GetById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _nextId++;
        _recipes.Add(recipe);
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is null || stars is < 1 or > 5) return;

        var totalStars = recipe.AverageRating * recipe.RatingCount + stars;
        recipe.RatingCount++;
        recipe.AverageRating = Math.Round(totalStars / recipe.RatingCount, 1);
    }
}

