toolArgs.file_text:
@using RecipeCommunity.Services
@inject RecipeService RecipeService

<div class="card mt-3">
    <div class="card-body">
        <h5 class="card-title">Rate this Recipe</h5>

        @if (hasRated)
        {
            <div class="alert alert-success mb-0">
                Thanks for rating! You gave this recipe @selectedRating star(s).
            </div>
        }
        else
        {
            <p class="mb-2">Click a star to rate:</p>
            <div style="font-size: 2rem; cursor: pointer; user-select: none;">
                @for (int i = 1; i <= 5; i++)
                {
                    var star = i;
                    <span class="@(star <= hoverRating ? "text-warning" : "text-muted")"
                          @onmouseover="() => hoverRating = star"
                          @onmouseout="() => hoverRating = 0"
                          @onclick="() => SubmitRating(star)"
                          role="button"
                          title="@star star(s)">★</span>
                }
            </div>
        }
    </div>
</div>

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private int hoverRating;
    private int selectedRating;
    private bool hasRated;

    private void SubmitRating(int stars)
    {
        RecipeService.AddRating(RecipeId, stars);
        selectedRating = stars;
        hasRated = true;
    }
}

